import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { BrowserRouter, Route, Routes } from "react-router-dom";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { AuthProvider } from "@/contexts/AuthContext";
import HomePage from "@/pages/HomePage";
import ParticipantsPage from "@/pages/ParticipantsPage";
import KeyFactsPage from "@/pages/KeyFactsPage";
import PainPointsPage from "@/pages/PainPointsPage";
import InitiativesHubPage from "@/pages/InitiativesHubPage";
import InitiativeCharterPage from "@/pages/InitiativeCharterPage";
import InitiativeCharterV2Page from "@/pages/ProjectChartersPage";
import RoadmapPage from "@/pages/RoadmapPage";
import DemoPage from "@/pages/DemoPage";
import AppLayout from "@/components/AppLayout";
import NotFound from "@/pages/NotFound";

const queryClient = new QueryClient();

function AppRoutes() {
  return (
    <Routes>
      <Route path="/demos/:tag" element={<DemoPage />} />
      <Route path="/" element={<AppLayout />}>
        <Route index element={<HomePage />} />
        <Route path="participantes" element={<ParticipantsPage />} />
        <Route path="factos" element={<KeyFactsPage />} />
        <Route path="pain-points" element={<PainPointsPage />} />
        <Route path="iniciativas" element={<InitiativesHubPage />} />
        <Route path="iniciativas/:id" element={<InitiativeCharterPage />} />
        <Route path="iniciativas-v2/:tag" element={<InitiativeCharterV2Page />} />
        <Route path="roadmap" element={<RoadmapPage />} />
      </Route>
      <Route path="*" element={<NotFound />} />
    </Routes>
  );
}

const App = () => (
  <QueryClientProvider client={queryClient}>
    <TooltipProvider>
      <Toaster />
      <AuthProvider>
        <BrowserRouter>
          <AppRoutes />
        </BrowserRouter>
      </AuthProvider>
    </TooltipProvider>
  </QueryClientProvider>
);

export default App;

import { NavLink, useLocation } from "react-router-dom";
import { Home, BarChart3, AlertTriangle, Lightbulb, Map, Network, ChevronLeft, ChevronRight, LogOut } from "lucide-react";
import { useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import t4hLogo from "@/assets/t4h_logo.png";
import ltplabsLogo from "@/assets/ltplabs-logo.svg";

const navItems = [
  { to: "/", label: "Homepage", icon: Home, end: true },
  // { to: "/participantes", label: "Participantes", icon: Users },
  { to: "/factos", label: "Fichas de Processos", icon: BarChart3 },
  { to: "/pain-points", label: "Pain-Points", icon: AlertTriangle },
  { to: "/iniciativas", label: "Initiatives Hub", icon: Lightbulb },
  { to: "/roadmap", label: "Roadmap", icon: Map },
  // { to: "/camadas-dados", label: "Mapa de Dados", icon: Network },
  // { to: "/timeline", label: "Timeline & Next Steps", icon: Calendar },
];

export default function AppSidebar() {
  const [collapsed, setCollapsed] = useState(false);
  const { logout } = useAuth();
  const location = useLocation();

  return (
    <aside className={`nav-sidebar flex flex-col transition-all duration-300 ${collapsed ? "w-16" : "w-64"} shrink-0 sticky top-0 h-screen`}>
      {/* Logo */}
      <div className="p-4 flex items-center gap-3 border-b border-sidebar-border">
        <img src={t4hLogo} alt="Tech4Home" className={`${collapsed ? "w-8" : "w-24"} h-auto object-contain brightness-0 invert`} />
        {!collapsed && <span className="text-xs font-medium opacity-70 leading-tight">AI Operational<br />Design & Roadmap</span>}
      </div>

      {/* Navigation */}
      <nav className="flex-1 py-4 px-2 space-y-1 overflow-y-auto">
        {navItems.map((item) => {
          const isActive = item.end ? location.pathname === item.to : location.pathname.startsWith(item.to);
          return (
            <NavLink
              key={item.to}
              to={item.to}
              end={item.end}
              className={`nav-item ${isActive ? "active" : ""} ${collapsed ? "justify-center px-2" : ""}`}
            >
              <item.icon className="h-4 w-4 shrink-0" />
              {!collapsed && <span>{item.label}</span>}
            </NavLink>
          );
        })}
      </nav>

      {/* Footer */}
      <div className="mt-auto border-t border-sidebar-border">
        {!collapsed && (
          <div className="px-4 py-3 flex items-center gap-2 opacity-60">
            <img src={ltplabsLogo} alt="LTPlabs" className="h-5 brightness-0 invert" />
            <span className="text-[10px]">Powered by LTPlabs</span>
          </div>
        )}
        <div className="px-2 py-2 flex items-center gap-2">
          {!collapsed && (
            <button onClick={logout} className="nav-item flex-1 text-xs opacity-70 hover:opacity-100">
              <LogOut className="h-3.5 w-3.5" />
              <span>Sair</span>
            </button>
          )}
          <button
            onClick={() => setCollapsed(!collapsed)}
            className="p-2 rounded-lg opacity-50 hover:opacity-100 transition-opacity"
          >
            {collapsed ? <ChevronRight className="h-4 w-4" /> : <ChevronLeft className="h-4 w-4" />}
          </button>
        </div>
      </div>
    </aside>
  );
}

import React, { createContext, useContext } from "react";

type AuthContextValue = {
  isAuthenticated: boolean;
  isAuthorized: boolean;
  account: null;
  login: () => Promise<void>;
  logout: () => Promise<void>;
};

const AuthContext = createContext<AuthContextValue | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const value: AuthContextValue = {
    isAuthenticated: true,
    isAuthorized: true,
    account: null,
    login: async () => {},
    logout: async () => {},
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within AuthProvider");
  }
  return context;
}

import { createRoot } from "react-dom/client";
import App from "./App";
import "./index.css";

createRoot(document.getElementById("root")!).render(<App />);

